package hello

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/hello"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type HelloProxy struct {
	hello.UnimplementedHelloServer
	client hello.HelloClient
}

func init() {
	proxyutil.Register(&hello.Hello_ServiceDesc, NewHelloProxy)
}
func NewHelloProxy(cc grpc.ClientConnInterface) hello.HelloServer {
	return &HelloProxy{client: hello.NewHelloClient(cc)}
}
func (p *HelloProxy) Ping(ctx context.Context, in *hello.PingMessage) (*hello.PingMessage, error) {
	return proxyutil.ProxyMethod[hello.PingMessage, hello.PingMessage](p.client.Ping)(ctx, in)
}
